import{_ as e,o as t,c as o,b as a}from"./app.3af72c35.js";const f=JSON.parse('{"title":"Theory","description":"","frontmatter":{"title":"Theory","subtitle":"All the knowledge of music becoming visible with the simple color coding system","cover":"tonnetz.svg","date":"2021-10-30T00:00:00.000Z"},"headers":[],"relativePath":"theory/index.md"}'),r={name:"theory/index.md"},s=a('<p>This is the main music theory research hub for establishing the Chromatone interpretation of some basic and also quite profound concepts.</p><p>We start from the very beginning - the physical world around us and the ways we can perceive and interpret it. What is <a href="./color/">Light and Color</a> and how do we see it? What is <a href="./sound/">Sound</a> and how do we hear it? This gives us the firm foundation for building more and more intricate structures on top of it.</p><p>Some sounds are more musical than others and we soon find the importance of their frequency profile. <a href="./notes/">Notes</a> are born from distinguishing particular sound pitches. And then all the combinations arise.</p><p>Two notes form <a href="./intervals/">Intervals</a> and three or more of them from <a href="./chords/">Chords</a>. If there&#39;s too many sounds to be played simultaneously, but still they have pleasant relations to one another, we talk about <a href="./scales/">Scales</a>.</p><p>Then we start organizing all these sound structures in time based on <a href="./rhythm/">Rhythm</a> and dive deep into <a href="./harmony/">Harmony</a> and <a href="./melody/">Melody</a> that evolve naturally to the whole <a href="./composition/">Composition</a> level.</p><p>There&#39;s quite a deep research here, and there&#39;s more <a href="./resources/">External resources</a> to explore for those, who needs to learn even more about music theory themselves.</p>',6),n=[s];function i(h,d,l,c,m,p){return t(),o("div",null,n)}var _=e(r,[["render",i]]);export{f as __pageData,_ as default};
